import { useEffect } from "react"
import "./news.css"
import { useRef } from "react"
import { useState } from "react"
import { useLocation, useNavigate } from "react-router-dom"
function News() {
    const navigate = useNavigate()
    let ref = useRef([])
    const interests = [
        "Business",
        "Entertainment",
        "General",
        "Health",
        "Science",
        "Sports",
        "Technology"
    ]
    let [selecteditems, changeselected] = useState([])
    let [savebackres, changeback] = useState()
    async function clickinterests(item, index) {
         await fetch("http://localhost:5000/sessioninterests", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                credentials: "include",
                body: JSON.stringify({selectedtopics: selecteditems})
            })
       ref.current.map((item, indexitem) => {
            if(index == indexitem) {
                if(item.style.borderColor == "rgba(90, 180, 255, 0.9)") {
                    item.style.border = "1px solid rgba(48, 95, 200, 0.45)"
                    item.style.boxShadow = "none"
                    
                }
                else {
                    item.style.borderColor = "rgba(90, 180, 255, 0.9)"
                    item.style.boxShadow = "0 0 12px rgba(70, 150, 255, 0.35)"
                  
                }
            }
        })
changeselected(cuurent => 
    cuurent.includes(item) ?
     cuurent.filter(i => i !== item)
     :
     [...cuurent, item]
)

    }
    useEffect(() => {
        async function getbackdata() {
         let fetchres = await fetch("http://localhost:5000/sendinterests", {
                method: "GET",
                headers: { "Content-Type": "application/json" },
                credentials: "include",
            })
            let jsonres = await fetchres.json()
            changeback(jsonres)
        }
        getbackdata()
    }, [])
    useEffect(() => {
        console.log(selecteditems)
        async function getbackdata() {
           
        }
        getbackdata()
    }, [selecteditems])
    async function continuebtn() {
     
        if(Object.values(savebackres)[0].length > 0)
        {
            navigate("/newsview", {state: {selectedtopics: Object.values(savebackres)}})
        }
    }
    return<>
        <div className="interest-page">
        <div className="interest-bg-left"></div>
        <div className="interest-bg-center"></div>
        <div className="interest-bg-right"></div>

        <div className="interest-container">
            <div className="interest-header">
            <h1>Select Your Interests</h1>
            <p>Choose topics you want to see in your feed</p>
            </div>

            <div className="interest-grid">
            {interests.map((interest, index) => (
                <div
                    key={index}
                    className="interest-card"
                    ref={(el) => (ref.current[index] = el)}
                    onClick={() => clickinterests(interest, index)}
                    >
                    {interest}
                     </div>
            ))}
            </div>

            <button onClick={() => continuebtn()} className="interest-button">Continue</button>
        </div>
        </div>
    </>
}
export default News
